sql:
SELECT MAX(available_space) AS max_available_space
FROM video_storage
WHERE retention_period >= 30;

SELECT DISTINCT al.camera_id
FROM access_logs al
WHERE al.access_time BETWEEN '2023-01-01' AND '2023-12-31';

SELECT camera_id, SUM(available_space) AS available_space_sum, SUM(total_space) AS total_space_sum
FROM video_storage
GROUP BY camera_id;

SELECT resolution, status
FROM camera_settings
WHERE status = 'active';

